import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Paths;

public class PathTraversalExample {

    public static void main(String[] args) {
        String userInput = "../etc/passwd"; // User input containing path traversal
        String directory = "/var/www/html/files/"; // Base directory for file access

        String filePath = directory + userInput;

        try {
            File file = new File(filePath);
            if (file.exists()) {
                byte[] fileContent = Files.readAllBytes(Paths.get(file.getPath()));
                System.out.println(new String(fileContent));
            } else {
                System.out.println("File not found.");
            }
        } catch (IOException e) {
            System.err.println("Error reading file: " + e.getMessage());
        }
    }
}

